package unverified;

import metadata.BehavioralDifference;
import metadata.DifferenceType;

import org.junit.jupiter.api.Test;

import static unverified.ClonePairAliasAwareInvocationTestSupport.*;
import static org.junit.jupiter.api.Assertions.assertNotEquals;
import static org.junit.jupiter.api.Assertions.assertTrue;

class ClonePair3811DifferenceFindingTest {

    private final ClonePair3811 subject = new ClonePair3811();

    /**
     * Generated by Codex (GPT-5).
     * Difference type: exception.
     * Difference manifestation: the methods differ in thrown exceptions or normal completion.
     * separating case: novel_0_2 ["new char[]{' ', '\\u00A0'}", "1", "1", "new char[]{}"]
     */
    @Test
    @BehavioralDifference(DifferenceType.EXCEPTION)
    void methodsDisagreeOnGeneratedInput() {
        InvocationOutcome method1Outcome = captureWithTimeout(values -> subject.method1((char[]) values[0], ((Integer) values[1]).intValue(), ((Integer) values[2]).intValue(), (char[]) values[3]), 1000L, buildMethod1Inputs());
        InvocationOutcome method2Outcome = captureWithTimeout(values -> subject.method2((char[]) values[0], ((Integer) values[1]).intValue(), ((Integer) values[2]).intValue(), (char[]) values[3]), 1000L, buildMethod2Inputs());

        assertCoreOutcome(
            method1Outcome,
            "EX",
            null,
            "java.lang.ArrayIndexOutOfBoundsException",
            "java.lang.Object[][char[][ ,  ],Integer(1),Integer(1),char[][]]",
            "java.lang.Object[][char[][ ,  ],Integer(1),Integer(1),char[][]]"
        );
        assertCoreOutcome(
            method2Outcome,
            "EX",
            null,
            "java.lang.StringIndexOutOfBoundsException",
            "java.lang.Object[][char[][ ,  ],Integer(1),Integer(1),char[][]]",
            "java.lang.Object[][char[][ ,  ],Integer(1),Integer(1),char[][]]"
        );
        assertTextEquals("stdout", "", method1Outcome.stdout);
        assertTextEquals("stdout", "", method2Outcome.stdout);
        assertTextEquals("stderr", "", method1Outcome.stderr);
        assertTextEquals("stderr", "", method2Outcome.stderr);
    }

    private Object[] buildMethod1Inputs() {
        return new Object[]{new char[]{' ', '\u00A0'}, 1, 1, new char[]{}};
    }

    private Object[] buildMethod2Inputs() {
        return new Object[]{new char[]{' ', '\u00A0'}, 1, 1, new char[]{}};
    }

}
